package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.assertEquals;

import org.junit.jupiter.api.Test;

class LineItemTest {

  @Test
  void testGetCurrencyCode() throws Exception {
    String expectedCurrencyCode = "USD";
    com.google.gson.examples.android.model.LineItem lineItem = new com.google.gson.examples.android.model.LineItem("itemName", 5, 10000L, expectedCurrencyCode);

    // Use reflection to invoke private field 'currencyCode' to verify it is set correctly
    java.lang.reflect.Field currencyCodeField = com.google.gson.examples.android.model.LineItem.class.getDeclaredField("currencyCode");
    currencyCodeField.setAccessible(true);
    String actualCurrencyCodeField = (String) currencyCodeField.get(lineItem);
    assertEquals(expectedCurrencyCode, actualCurrencyCodeField);

    // Directly test the public getter method
    String actualCurrencyCode = lineItem.getCurrencyCode();
    assertEquals(expectedCurrencyCode, actualCurrencyCode);
  }
}
